/**
 * Read a parsed tree node into a typed NodeData.
 * Recursively hydrates all fields and children via wrap functions.
 * Attaches byte range for .toEdit() and .replace().
 */
export function readNode<K extends NodeKind<PythonGrammar>>(target: TreeNode<K>): Simplify<NodeData<K> & { toEdit(): Edit; replace(): Edit; render(): string }> {
  const fn = _wrapTable[target.type];
  if (!fn) throw new Error(`No wrap function for kind '${target.type}' in PythonGrammar grammar`);
  return fn(target) as Simplify<NodeData<K> & { toEdit(): Edit; replace(): Edit; render(): string }>;
}

/**
 * Create an in-place editor for a parsed tree node.
 * Alias for readNode() — kept for backward compatibility.
 */
export const edit = readNode;
